                      .Select(t=>t.Subject).ToList();
var orphans = classes.Where(c => !g.Triples.Any(t => t.Subject.Equals(c) && !t.Predicate.Equals(RDF_TYPE))).ToList();
Console.WriteLine($"Classes declarees : {classes.Count}, orphelines : {orphans.Count}");

