// MĂŠthode 2 : URI avec prĂŠfixe (QName) - nĂŠcessite un namespace dĂŠclarĂŠ
g.NamespaceMap.AddNamespace("ex", UriFactory.Create("http://example.org/"));
IUriNode knows = g.CreateUriNode("ex:knows");
