// CrĂŠation d'une liste RDF ordonnĂŠe [Alice, Bob, Charlie]
// AssertList gĂŠnĂ¨re une chaĂŽne de nĹuds blancs reliĂŠs par rdf:first et rdf:rest
IGraph g = new Graph();
var root = g.AssertList(new List<INode>() { "Alice".ToLiteral(g), "Bob".ToLiteral(g), "Charlie".ToLiteral(g) });


// Fonction utilitaire pour afficher uniquement la valeur textuelle de chaque noeud littĂŠral
Func<IEnumerable<INode>, string> fmt = nodes => string.Join(", ", nodes.Select(n => ((ILiteralNode)n).Value));

Console.WriteLine($"Initial          : [{fmt(g.GetListItems(root))}]");

// AddToList insĂ¨re "Diana" en fin de liste en ajoutant un nĹud blank supplĂŠmentaire
g.AddToList(root, new List<INode>() { "Diana".ToLiteral(g) });
Console.WriteLine($"Apres ajout      : [{fmt(g.GetListItems(root))}]");

// RemoveFromList supprime toutes les occurrences de "Bob" dans la liste
g.RemoveFromList(root, new List<INode>() { "Bob".ToLiteral(g) });
Console.WriteLine($"Apres suppression: [{fmt(g.GetListItems(root))}]");

