PREFIX bd: <http://www.bigdata.com/rdf#>

SELECT ?cityLabel ?population
WHERE {
    ?city wdt:P31 wd:Q515 ;
          wdt:P17 wd:Q142 ;
          wdt:P1082 ?population .

