if SPARQLWRAPPER_AVAILABLE:
    # Exercice 1 : Universites francaises via Wikidata
    import time

    sparql_uni = SPARQLWrapper("https://query.wikidata.org/sparql")
    sparql_uni.setReturnFormat(JSON)
    sparql_uni.agent = "CoursIA-SemanticWeb-Notebook/1.0 (educational)"

    sparql_uni.setQuery("""
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?universityLabel ?students
WHERE {
    ?university wdt:P31 wd:Q3918 ;
                wdt:P17 wd:Q142 ;
                wdt:P2196 ?students ;
                rdfs:label ?universityLabel .
    FILTER(lang(?universityLabel) = "fr")
}
ORDER BY DESC(?students)
LIMIT 10
""")

    try:
        # WDQS applique une limite ~1 requete/minute, renforcee sous charge.
        # rdfs:label + FILTER est plus fiable que SERVICE wikibase:label (rejete
        # sous charge) ; on ajoute un backoff pour robustesse (cellule = 2e
        # requete Wikidata consecutive apres la cellule 25).
        results_uni = None
        for attempt in range(4):
            try:
                time.sleep(60)
                results_uni = sparql_uni.query().convert()
                break
            except Exception as e_retry:
                if attempt < 3:
                    print(f"  (tentative {attempt + 1}/4) WDQS : {type(e_retry).__name__}, nouvel essai dans 60s...")
                else:
