# Exercice 3 : ProductShape avec severites et sh:or

product_shapes_ttl = """
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .
@prefix ex: <http://example.org/> .
@prefix schema: <http://schema.org/> .

ex:ProductShape a sh:NodeShape ;
    sh:targetClass ex:Product ;

    # Nom : obligatoire, chaine, min 2 caracteres (Violation)
    sh:property [
        sh:path schema:name ;
        sh:minCount 1 ;
        sh:datatype xsd:string ;
        sh:minLength 2 ;
        sh:severity sh:Violation ;
        sh:message "Le nom est obligatoire (string, min 2 caracteres)"@fr ;
    ] ;

    # Prix : obligatoire, entre 0 et 100000 (Violation)
    sh:property [
        sh:path schema:price ;
        sh:minCount 1 ;
        sh:minInclusive 0 ;
        sh:maxInclusive 100000 ;
        sh:severity sh:Violation ;
        sh:message "Le prix est obligatoire et doit etre entre 0 et 100000"@fr ;
    ] ;

    # Categorie : recommandee (Warning)
    sh:property [
        sh:path schema:category ;
        sh:minCount 1 ;
        sh:severity sh:Warning ;
        sh:message "La categorie est recommandee"@fr ;
    ] ;

    # Description : suggeree, min 10 caracteres (Info)
    sh:property [
        sh:path schema:description ;
        sh:minLength 10 ;
        sh:severity sh:Info ;
        sh:message "Une description d'au moins 10 caracteres est suggeree"@fr ;
    ] ;

    # Contrainte logique : une marque OU un fabricant
    sh:or (
        [ sh:path schema:brand ; sh:minCount 1 ]
        [ sh:path schema:manufacturer ; sh:minCount 1 ]
    ) ;
    sh:message "Un produit doit avoir une marque (brand) ou un fabricant (manufacturer)"@fr .
"""

product_shapes = Graph()
product_shapes.parse(data=product_shapes_ttl, format="turtle")

# Donnees de test
product_data = Graph()
product_data.bind("ex", EX)
product_data.bind("schema", SCHEMA)

# Produit valide : nom, prix, categorie, description longue, et une marque
product_data.add((EX.prod1, RDF.type, EX.Product))
product_data.add((EX.prod1, SCHEMA.name, Literal("Clavier mecanique")))
product_data.add((EX.prod1, SCHEMA.price, Literal(89, datatype=XSD.integer)))
product_data.add((EX.prod1, SCHEMA.category, Literal("Peripheriques")))
product_data.add((EX.prod1, SCHEMA.description, Literal("Clavier mecanique retroeclaire avec switches bleus")))
product_data.add((EX.prod1, SCHEMA.brand, Literal("KeyCo")))

# Produit invalide :
# - nom trop court "X" (Violation)
# - prix hors bornes 200000 (Violation)
# - ni marque ni fabricant (Violation via sh:or)
# - pas de categorie (Warning)
# - description trop courte "court" (Info)
product_data.add((EX.prod2, RDF.type, EX.Product))
product_data.add((EX.prod2, SCHEMA.name, Literal("X")))
product_data.add((EX.prod2, SCHEMA.price, Literal(200000, datatype=XSD.integer)))
product_data.add((EX.prod2, SCHEMA.description, Literal("court")))

# Validation
conforms_prod, results_prod, text_prod = validate(
    product_data, shacl_graph=product_shapes, inference='rdfs', abort_on_first=False
)
print(f"Conforme : {conforms_prod}")
print()
print(text_prod)

# Exercice final : Valider un dataset bibliotheque avec SHACL
from rdflib import Graph, Namespace, Literal
from rdflib.namespace import DC, RDF, XSD
from pyshacl import validate

SH = Namespace("http://www.w3.org/ns/shacl#")
EX = Namespace("http://example.org/")

# Forme SHACL pour une notice bibliographique
biblio_shapes_ttl = r"""
@prefix sh:  <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .
@prefix ex:  <http://example.org/> .
@prefix dc:  <http://purl.org/dc/elements/1.1/> .

ex:BibliographicRecordShape a sh:NodeShape ;
    sh:targetClass ex:BibliographicRecord ;

    # Titre : exactement 1, type string
    sh:property [
        sh:path dc:title ;
        sh:minCount 1 ;
        sh:maxCount 1 ;
        sh:datatype xsd:string ;
        sh:message "Une notice doit avoir exactement un titre (string)"@fr ;
    ] ;

    # Createur : au moins 1
    sh:property [
        sh:path dc:creator ;
        sh:minCount 1 ;
        sh:message "Une notice doit avoir au moins un createur"@fr ;
    ] ;

    # Date : motif YYYY-MM-DD
    sh:property [
        sh:path dc:date ;
        sh:pattern "^\\d{4}-\\d{2}-\\d{2}$" ;
        sh:message "La date doit etre au format YYYY-MM-DD"@fr ;
    ] ;

    # Type : parmi Book, Article, Thesis
    sh:property [
        sh:path dc:type ;
        sh:in ( "Book" "Article" "Thesis" ) ;
        sh:message "Le type doit etre Book, Article ou Thesis"@fr ;
    ] ;

    # Langue : facultative (au plus une valeur)
    sh:property [
        sh:path dc:language ;
        sh:maxCount 1 ;
        sh:message "Une seule langue au maximum"@fr ;
    ] .
"""

biblio_shapes = Graph()
biblio_shapes.parse(data=biblio_shapes_ttl, format="turtle")

# Donnees de test (2 valides, 1 invalide)
biblio_data = Graph()
biblio_data.bind("ex", EX)
biblio_data.bind("dc", DC)

# Notice valide 1 (complete)
biblio_data.add((EX.rec1, RDF.type, EX.BibliographicRecord))
biblio_data.add((EX.rec1, DC.title, Literal("Le Web Semantique", datatype=XSD.string)))
biblio_data.add((EX.rec1, DC.creator, Literal("Jean Dupont")))
biblio_data.add((EX.rec1, DC.date, Literal("2021-05-12")))
biblio_data.add((EX.rec1, DC.type, Literal("Book")))
biblio_data.add((EX.rec1, DC.language, Literal("fr")))

# Notice valide 2 (plusieurs createurs, sans langue -> facultative)
biblio_data.add((EX.rec2, RDF.type, EX.BibliographicRecord))
biblio_data.add((EX.rec2, DC.title, Literal("Introduction a RDF", datatype=XSD.string)))
biblio_data.add((EX.rec2, DC.creator, Literal("Alice Martin")))
biblio_data.add((EX.rec2, DC.creator, Literal("Bob Durand")))
biblio_data.add((EX.rec2, DC.date, Literal("2019-11-03")))
biblio_data.add((EX.rec2, DC.type, Literal("Article")))

# Notice invalide : pas de createur, date mal formee, type hors liste
biblio_data.add((EX.rec3, RDF.type, EX.BibliographicRecord))
biblio_data.add((EX.rec3, DC.title, Literal("Notice incomplete", datatype=XSD.string)))
biblio_data.add((EX.rec3, DC.date, Literal("12/05/2021")))
biblio_data.add((EX.rec3, DC.type, Literal("Magazine")))

# Validation
conforms_biblio, results_biblio, text_biblio = validate(
    biblio_data, shacl_graph=biblio_shapes, inference='rdfs', abort_on_first=False
)
print(f"Conforme : {conforms_biblio}")
print()
print(text_biblio)

